// Build Claude messages with session memory + proper system/messages split.
// Memory lives in n8n's workflow-global staticData, keyed by sessionId.
// We trim to last 20 messages (10 turns) to keep context window bounded.

const MAX_HISTORY_MESSAGES = 20;

// ── 1. Inputs ────────────────────────────────────────────────────────────────
const inputItem = $input.first();
const body = inputItem.json.body || inputItem.json;
const userMessage = (body.message || '').toString().trim();
const sessionId = (body.sessionId || body.session_id || '').toString().trim();

if (!userMessage) {
  throw new Error('No user message provided in webhook body');
}
if (!sessionId) {
  // No sessionId means fresh conversation. Generate one; client must echo it back next turn.
  // (Alternative: reject the request and force the client to provide one.)
}
const effectiveSessionId = sessionId || `anon-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

// ── 2. Knowledge base — read from the Drive node's binary output ────────────
let knowledgeBase = '';
if (inputItem.binary && inputItem.binary.data) {
  knowledgeBase = Buffer.from(inputItem.binary.data.data, 'base64').toString('utf-8');
} else {
  // Fall back to empty KB rather than failing — assistant can still answer generally.
  knowledgeBase = '(Knowledge base unavailable — answer from general knowledge and refer the user to hello@certainid.io)';
}

// ── 3. Conversation memory ──────────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};
const session = staticData.sessions[effectiveSessionId] || { messages: [], lastSeen: 0 };

// Trim very old sessions (>24h) to prevent unbounded growth.
const now = Date.now();
for (const sid of Object.keys(staticData.sessions)) {
  if (now - (staticData.sessions[sid].lastSeen || 0) > 24 * 60 * 60 * 1000) {
    delete staticData.sessions[sid];
  }
}

// ── 4. Build messages array (history + current user turn) ──────────────────
const history = (session.messages || []).slice(-MAX_HISTORY_MESSAGES);
const messages = [...history, { role: 'user', content: userMessage }];

// ── 5. System prompt — KB lives here (not in user message); enables prompt caching ─
const systemPrompt = `You are CertainID's helpful concierge — a friendly, knowledgeable assistant who explains the product in plain English. CertainID is a privacy-first biometric identity verification platform that uses blockchain to combat deepfakes.

GUIDELINES:
- Speak conversationally. Do not read lists aloud — turn them into natural sentences.
- Be concise. Two or three sentences for simple questions; longer only when the user asks for detail.
- If the user asks about something not in the knowledge base, give a brief general answer and suggest they email hello@certainid.io for specifics. Do not invent details.
- Maintain the conversation thread. Reference what the user said earlier when relevant.
- Never break character or mention that you are an AI, Claude, or a chatbot unless the user directly asks.

KNOWLEDGE BASE:
${knowledgeBase}`;

return {
  systemPrompt,
  messages,
  sessionId: effectiveSessionId,
  userMessage,
};

// Persist this turn to session memory, format the response for the webhook.

const apiResponse = $input.first().json;
const assistantMessage = apiResponse.content && apiResponse.content[0] && apiResponse.content[0].text
  ? apiResponse.content[0].text
  : '(Assistant returned no text — please try again)';

// Recover the sessionId + user message from the Build Messages node.
const built = $('Build Claude Messages').first().json;
const sessionId = built.sessionId;
const userMessage = built.userMessage;

// Append this turn to staticData.
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};
if (!staticData.sessions[sessionId]) staticData.sessions[sessionId] = { messages: [], lastSeen: 0 };
staticData.sessions[sessionId].messages.push(
  { role: 'user', content: userMessage },
  { role: 'assistant', content: assistantMessage }
);
staticData.sessions[sessionId].lastSeen = Date.now();

// Trim — keep last 20 messages (10 turns) max per session.
const MAX = 20;
if (staticData.sessions[sessionId].messages.length > MAX) {
  staticData.sessions[sessionId].messages = staticData.sessions[sessionId].messages.slice(-MAX);
}

return {
  message: assistantMessage,
  sessionId,
  timestamp: new Date().toISOString(),
};
